## Type Mappings

### API → Component Types

```typescript
// services/users.ts - API types from @workspace/api-client-ts
import type { 
  StudentResponse,           // { id, username, email, name, lastname, isActive, createdAt, updatedAt }
  StudentListResponse,       // { success, message, data: StudentResponse[], error }
  TeacherProfileResponse,    // { id, username, name, lastname, email, department, contactPhone, avatarUrl, isActive, createdAt, updatedAt }
  TeacherSettingsResponse,  // { theme, notificationsEnabled, notificationFrequency, interfaceLanguage }
} from "@workspace/api-client-ts";

// types/student.interface.ts - Component types
interface Student {
  id: string;                           // ← map from: number (API) - convert to string
  name: string;                         // ← map from: name + " " + lastname (API)
  email: string;                         // ← map from: email (API)
  maxLevel: number;                      // ← NOT in API - add default 0
  status: "active" | "inactive" | "unregistered";  // ← map from: isActive (API)
  registrationDate: string;              // ← map from: createdAt (API) - format date
  lastActivity: string;                  // ← NOT in API - add default registrationDate
  completedLessons: number;              // ← NOT in API - add default 0
  totalLessons: number;                  // ← NOT in API - add default 40
  progress: number;                       // ← NOT in API - add default 0
  achievements: string[];                // ← NOT in API - add default []
  course?: string;                        // ← NOT in API - add default "2024-2027"
}
```

### Adapter Function Pattern

```typescript
// src/lib/adapters/student.adapter.ts
import type { StudentResponse } from "@workspace/api-client-ts";
import type { Student } from "@/types";

export function studentResponseToStudent(response: StudentResponse): Student {
  return {
    id: String(response.id),
    name: `${response.name} ${response.lastname}`.trim(),
    email: response.email,
    maxLevel: 0,  // Not available in API
    status: response.isActive ? "active" : "inactive",
    registrationDate: response.createdAt 
      ? new Date(response.createdAt).toISOString().split("T")[0]
      : new Date().toISOString().split("T")[0],
    lastActivity: response.createdAt 
      ? new Date(response.createdAt).toISOString().split("T")[0]
      : new Date().toISOString().split("T")[0],
    completedLessons: 0,
    totalLessons: 40,
    progress: 0,
    achievements: [],
    course: "2024-2027",  // TODO: will come from LMS or settings
  };
}
```

## Target State: services/users.ts

```typescript
import { cookies } from "next/headers";
import {
  Configuration,
  UsersApi,
  StudentListResponse,
  StudentResponse,
  StudentCreate,
  StudentUpdate,
  TeacherProfileResponse,
  TeacherSettingsResponse,
} from "@workspace/api-client-ts";

const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";

async function getAuthToken(): Promise<string> {
  const cookieStore = await cookies();
  // FIX: Changed from "access_token" to "auth_token" (matches backend)
  const token = cookieStore.get("auth_token");
  return token?.value || "";
}

function createUsersApiConfiguration(token?: string): Configuration {
  return new Configuration({
    basePath: API_BASE_URL,
    accessToken: token,
  });
}

// FIX: No async function for accessToken - synchronous
function getUsersApi(token?: string): UsersApi {
  return new UsersApi(createUsersApiConfiguration(token));
}

export interface GetStudentsParams {
  skip?: number;
  limit?: number;
  search?: string;
}

export async function getStudents(params: GetStudentsParams = {}): Promise<StudentListResponse> {
  const token = await getAuthToken();
  const api = getUsersApi(token);
  const response = await api.listStudentsApiV1UsersStudentsGet({
    skip: params.skip,
    limit: params.limit,
    search: params.search,
  });
  return response;
}

export async function getStudent(id: number): Promise<StudentResponse> {
  const token = await getAuthToken();
  const api = getUsersApi(token);
  const response = await api.getStudentApiV1UsersStudentsIdGet({ id });
  return response.data;  // Unwrap from wrapper
}

export async function createStudent(studentCreate: StudentCreate): Promise<StudentResponse> {
  const token = await getAuthToken();
  const api = getUsersApi(token);
  const response = await api.createStudentApiV1UsersStudentsPost({ studentCreate });
  return response.data;  // Unwrap from wrapper
}

// Teacher Profile - unwrap Schema to Response
export async function getTeacherProfile(): Promise<TeacherProfileResponse> {
  const token = await getAuthToken();
  const api = getUsersApi(token);
  const response = await api.getTeacherProfileApiV1UsersProfessorsMeGet();
  return response.data;  // Unwrap from TeacherProfileResponseSchema
}

export async function updateTeacherProfile(profile: TeacherProfileResponse): Promise<TeacherProfileResponse> {
  const token = await getAuthToken();
  const api = getUsersApi(token);
  const response = await api.updateTeacherProfileApiV1UsersProfessorsMePut({ 
    teacherProfileUpdate: profile 
  });
  return response.data;
}

// Teacher Settings - unwrap Schema to Response  
export async function getTeacherSettings(): Promise<TeacherSettingsResponse> {
  const token = await getAuthToken();
  const api = getUsersApi(token);
  const response = await api.getTeacherSettingsApiV1UsersProfessorsSettingsGet();
  return response.data;  // Unwrap from TeacherSettingsResponseSchema
}

export async function updateTeacherSettings(settings: TeacherSettingsResponse): Promise<TeacherSettingsResponse> {
  const token = await getAuthToken();
  const api = getUsersApi(token);
  const response = await api.updateTeacherSettingsApiV1UsersProfessorsSettingsPut({ 
    teacherSettingsUpdate: settings 
  });
  return response.data;
