## Target State: student-data-provider.tsx

```typescript
// REMOVE: All mock data (lines 6-88)
// REMOVE: getStudentCached, getAllStudentsCached, getStudentsListCached functions
// MODIFY: getStudent, getAllStudents, getStudents, getUniqueCourses to use real API

import { notFound } from "next/navigation";
import { unstable_cache } from 'next/cache';
import { usersService } from "@/services/users";
import { studentResponseToStudent } from "@/lib/adapters/student.adapter";

const cacheOptions = { 
  revalidate: process.env.NODE_ENV === 'production' ? 300 : 60,
  tags: ['students'] 
};

// Cache key prefixes for revalidation
const CACHE_KEYS = {
  student: 'student-detail',
  allStudents: 'all-students',
  studentsList: 'students-list',
} as const;

const getStudentsCached = unstable_cache(
  async () => {
    const response = await usersService.getStudents();
    return response.data.map(studentResponseToStudent);
  },
  [CACHE_KEYS.allStudents],
  cacheOptions
);

const getStudentCached = unstable_cache(
  async (id: string) => {
    const student = await usersService.getStudent(parseInt(id, 10));
    return studentResponseToStudent(student);
  },
  [CACHE_KEYS.student],
  { ...cacheOptions, keys: [CACHE_KEYS.student, (id: string) => id] }
);

// Export: getStudent for student detail page
export async function getStudent(id: string) {
  return getStudentCached(id);
}

// Export: getAllStudents for analytics/reports
export async function getAllStudents() {
  return getStudentsCached();
}

// Export: getStudents for table (returns students with course field)
// NOTE: course field not in API - derive from registration date or use default
export async function getStudents() {
  const students = await getStudentsCached();

  // Enrich with course field (derived from registration date)
  return students.map(student => ({
    ...student,
    course: deriveCourseFromDate(student.registrationDate),
  }));
}

// Helper: Derive course year from registration date
function deriveCourseFromDate(dateStr: string): string {
  const year = new Date(dateStr).getFullYear();
  return `${year}-${year + 3}`;
}

// Export: getUniqueCourses - extract unique courses
export async function getUniqueCourses(): Promise<string[]> {
  const students = await getStudents();
  const courses = Array.from(new Set(students.map(s => s.course))).sort().reverse();
  return courses;
}
```

