## 2. Component Changes

### 2.1 `apps/frontend/src/lib/actions.ts` (MODIFY)

Add new server action after `changePasswordAction`:

```typescript
// 🔵 Schema de validación para actualización de perfil
const profileUpdateSchema = z.object({
  fullName: z.string().min(2, "Mínimo 2 caracteres").optional(),
  email: z.string().email("Email inválido").optional().or(z.literal("")),
  department: z.string().optional(),
  contactPhone: z.string().optional(),
});

export async function updateProfileAction(
  prevState: ActionState | null,
  formData: FormData
): Promise<ActionState> {
  try {
    const validatedFields = profileUpdateSchema.safeParse({
      fullName: formData.get("fullName"),
      email: formData.get("email"),
      department: formData.get("department"),
      contactPhone: formData.get("contactPhone"),
    });

    if (!validatedFields.success) {
      return {
        success: false,
        message: "Errores de validación",
        errors: validatedFields.error.flatten().fieldErrors,
      };
    }

    const cookieStore = await cookies();
    const token = cookieStore.get("auth_token")?.value;
    if (!token) {
      return { success: false, message: "No autenticado" };
    }

    const { getServerUser } = await import("@/lib/auth-server");
    const { user } = await getServerUser();
    if (!user || !user.id) {
      return { success: false, message: "No se pudo obtener la información del usuario" };
    }

    const { fullName, email, department, contactPhone } = validatedFields.data;

    const nameParts = fullName?.trim().split(/\s+/) || [];
    const name = nameParts[0] || "";
    const lastname = nameParts.slice(1).join(" ") || null;

    const { updateTeacherProfile } = await import("@/services/users");
    await updateTeacherProfile({
      name: name || undefined,
      lastname: lastname || undefined,
      email: email || undefined,
      department: department || undefined,
      contactPhone: contactPhone || undefined,
    });

    return { success: true, message: "Perfil actualizado exitosamente" };

  } catch (error: unknown) {
    console.error("Error updating profile:", error);
    const detail = (error as { detail?: string }).detail;
    const message = error instanceof Error ? error.message : "Error al actualizar el perfil";
    return {
      success: false,
      message,
      errors: { _form: [detail || message] },
    };
  }
}
```

